data.value:
decimal groupSumChicks = 0;
decimal groupSumCullsDead = 0;
decimal groupSumOfCullsDead = 0;
decimal groupSumOfTotalLoss = 0;
decimal groupSumOftotalCullsDead = 0;
decimal groupresultOfTotal = 0;
decimal groupresultOfTotalLoss = 0;
decimal groupSettedEggs = 0;
decimal percentage = 0;
decimal percentageBroiler = 0;
decimal percentageDestroyed = 0;
decimal percentageUnHatEggs = 0;
decimal percentageTotalLoss = 0;
decimal percentageTotal = 0;

private void xrTableCell30_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e)
{
    decimal fChicks = 0;
    decimal mChicks = 0;

    if (GetCurrentColumnValue("FChicks") != null && !string.IsNullOrEmpty(GetCurrentColumnValue("FChicks").ToString()))
        fChicks = Convert.ToDecimal(GetCurrentColumnValue("FChicks"));

    if (GetCurrentColumnValue("MChicks") != null && !string.IsNullOrEmpty(GetCurrentColumnValue("MChicks").ToString()))
        mChicks = Convert.ToDecimal(GetCurrentColumnValue("MChicks"));

    decimal result = fChicks + mChicks;

    XRTableCell cell = sender as XRTableCell;
    cell.Text = result.ToString("0"); 
}

private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e)
{
    decimal fChicks = 0, mChicks = 0, settedEggs = 0;

    if (GetCurrentColumnValue("FChicks") != null && !string.IsNullOrEmpty(GetCurrentColumnValue("FChicks").ToString()))
        fChicks = Convert.ToDecimal(GetCurrentColumnValue("FChicks"));

    if (GetCurrentColumnValue("MChicks") != null && !string.IsNullOrEmpty(GetCurrentColumnValue("MChicks").ToString()))
        mChicks = Convert.ToDecimal(GetCurrentColumnValue("MChicks"));

    groupSumChicks += (fChicks + mChicks);

    if (GetCurrentColumnValue("SettedEggs") != null && !string.IsNullOrEmpty(GetCurrentColumnValue("SettedEggs").ToString()))
        settedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));

    groupSettedEggs += settedEggs;

    if (groupSettedEggs != 0)
        percentage = (groupSumChicks * 100m) / groupSettedEggs;

    decimal chicks = 0;
    if (GetCurrentColumnValue("Chicks") != null && !string.IsNullOrEmpty(GetCurrentColumnValue("Chicks").ToString()))
        chicks = Convert.ToDecimal(GetCurrentColumnValue("Chicks"));

    if (groupSettedEggs != 0)
        percentageBroiler = (chicks * 100m) / groupSettedEggs;

    decimal DestroyedEggs = 0;
    if (GetCurrentColumnValue("DestroyedEggs") != null && !string.IsNullOrEmpty(GetCurrentColumnValue("DestroyedEggs").ToString()))
        DestroyedEggs = Convert.ToDecimal(GetCurrentColumnValue("DestroyedEggs"));

    if (groupSettedEggs != 0)
        percentageDestroyed = (DestroyedEggs * 100m) / groupSettedEggs;

    decimal UnHatEggs = 0;
    if (GetCurrentColumnValue("UnHatEggs") != null && !string.IsNullOrEmpty(GetCurrentColumnValue("UnHatEggs").ToString()))
        UnHatEggs = Convert.ToDecimal(GetCurrentColumnValue("UnHatEggs"));

    if (groupSettedEggs != 0)
        percentageUnHatEggs = (UnHatEggs * 100m) / groupSettedEggs;

    decimal fCulls = 0, mCulls = 0, fDead = 0, mDead = 0;

    if (GetCurrentColumnValue("FCulls") != null)
        fCulls = Convert.ToDecimal(GetCurrentColumnValue("FCulls"));

    if (GetCurrentColumnValue("MCulls") != null)
        mCulls = Convert.ToDecimal(GetCurrentColumnValue("MCulls"));

    if (GetCurrentColumnValue("FDead") != null)
        fDead = Convert.ToDecimal(GetCurrentColumnValue("FDead"));

    if (GetCurrentColumnValue("MDead") != null)
        mDead = Convert.ToDecimal(GetCurrentColumnValue("MDead"));

    groupSumCullsDead += (fCulls + mCulls + fDead + mDead);

    decimal Culls = 0, Dead = 0;

    if (GetCurrentColumnValue("Culls") != null)
        Culls = Convert.ToDecimal(GetCurrentColumnValue("Culls"));

    if (GetCurrentColumnValue("Dead") != null)
        Dead = Convert.ToDecimal(GetCurrentColumnValue("Dead"));

    groupSumOfCullsDead += (Culls + Dead);

    groupSumOftotalCullsDead = groupSumCullsDead + groupSumOfCullsDead;

    groupSumOfTotalLoss += (UnHatEggs + DestroyedEggs);

    groupresultOfTotalLoss = groupSumOftotalCullsDead + groupSumOfTotalLoss;

    if (groupSettedEggs != 0)
        percentageTotalLoss = (groupresultOfTotalLoss * 100m) / groupSettedEggs;

    decimal ChicksVal = 0;
    if (GetCurrentColumnValue("Chicks") != null)
        ChicksVal = Convert.ToDecimal(GetCurrentColumnValue("Chicks"));

    groupresultOfTotal = ChicksVal + groupSumOfTotalLoss + groupSumCullsDead + groupSumChicks;

    if (groupSettedEggs != 0)
        percentageTotal = (groupresultOfTotal * 100m) / groupSettedEggs;
}

private void xrTableCell55_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e)
{
    XRTableCell cell = sender as XRTableCell;
    cell.Text = groupSumChicks.ToString("0");
    groupSumChicks = 0;
}

